// Determine slot type from UTC hour (no Merge node needed)
// UTC 22 = KST 07:00 → morning slot (send at 09:00 KST)
// UTC 08 = KST 17:00 → evening slot (send at 19:00 KST)
const utc_hour = new Date().getUTCHours();
const is_morning = (utc_hour >= 20 && utc_hour <= 23);
const slot_type = is_morning ? 'morning' : 'evening';
const slot_hour = is_morning ? 9 : 19;

// Dedup by auth_user_id — keep one session per user
const seen = new Set();
const result = [];

for (const item of $input.all()) {
  const s = item.json;
  const profile = s.nv2_profiles;
  const product_session = s.nv2_product_sessions;
  const product = product_session?.nv2_learning_products;

  // Skip anonymous sessions
  if (s.auth_user_id?.startsWith('anon:')) continue;

  // Skip if no Discord account or DM unsubscribed
  if (!profile?.discord_id || profile.discord_dm_unsubscribed) continue;

  // Dedup — keep first (most recent due to order=updated_at.desc)
  if (seen.has(s.auth_user_id)) continue;
  seen.add(s.auth_user_id);

  const meta = typeof product?.meta === 'string'
    ? JSON.parse(product.meta)
    : (product?.meta ?? {});

  result.push({
    json: {
      slot_type,
      slot_hour,
      auth_user_id: s.auth_user_id,
      session_id: s.session_id,
      product_session_id: s.product_session_id,
      discord_id: profile.discord_id,
      display_name: profile.display_name || '학습자',
      timezone: profile.timezone || 'Asia/Seoul',
      session_number: product_session?.session_number ?? 1,
      session_label: `Session ${product_session?.session_number ?? ''}`.trim(),
      product_id: product?.id,
      product_name: product?.name ?? '',
      product_slug: product?.slug ?? '',
      is_story: !!(meta?.story),
    }
  });
}

return result;

const user = $input.item.json;

const utc_hour = new Date().getUTCHours();
const is_morning = (utc_hour >= 20 && utc_hour <= 23);
const slot_type = user.slot_type ?? (is_morning ? 'morning' : 'evening');
const slot_hour = user.slot_hour ?? (is_morning ? 9 : 19);

const timezone   = user.timezone ?? 'Asia/Seoul';
const auth_user_id      = user.auth_user_id;
const product_session_id = user.product_session_id;

const today_local = new Date().toLocaleDateString('en-CA', { timeZone: timezone });
const today_utc_start = new Date(`${today_local}T00:00:00.000Z`).toISOString();
const hour_tag = `cheer:${String(slot_hour).padStart(2, '0')}`;

const is_story = (() => {
  const meta = typeof user.product_meta === 'string'
    ? JSON.parse(user.product_meta)
    : (user.product_meta ?? {});
  return !!meta?.story;
})();

const product_name = user.product_name ?? '';
const session_label = `Session ${user.session_number ?? ''}`;

// SQL: dedup check
const dedup_sql = `SELECT schedule_id FROM nv2_schedules
WHERE auth_user_id = '${auth_user_id}'
  AND schedule_type = 'cheer'
  AND message_body LIKE '${hour_tag}|%'
  AND created_at >= '${today_utc_start}'
LIMIT 1`;

// SQL: completed session count
const count_sql = `SELECT COUNT(*) AS completed_count FROM nv2_sessions
WHERE auth_user_id = '${auth_user_id}'
  AND status = 'completed'`;

// SQL: learning content preview
const content_sql = is_story
  ? `SELECT c.card_type, c.card_data
     FROM nv2_product_session_stages pss
     JOIN nv2_stages st ON st.id = pss.stage_id
     JOIN nv2_cards  c  ON c.stage_id = st.id
     WHERE pss.product_session_id = '${product_session_id}'
       AND st.stage_type = 'story'
       AND c.card_type   = 'story'
     LIMIT 1`
  : `SELECT st.id AS stage_id, c.card_type, c.card_data
     FROM nv2_product_session_stages pss
     JOIN nv2_stages st ON st.id = pss.stage_id
     JOIN nv2_cards  c  ON c.stage_id = st.id
     WHERE pss.product_session_id = '${product_session_id}'
       AND st.stage_type = 'learning'
       AND c.card_type IN ('title', 'description')
     ORDER BY pss.display_order ASC, c.card_type ASC
     LIMIT 10`;

return [{
  json: {
    ...user,
    slot_type,
    slot_hour,
    hour_tag,
    today_local,
    is_story,
    product_name,
    session_label,
    dedup_sql,
    count_sql,
    content_sql,
  }
}];

const dedup_rows = $input.all();
// If any row returned, this slot is already queued — skip
if (dedup_rows.length > 0 && dedup_rows[0].json.schedule_id) {
  return [];
}
// Pass through the prepared query data from Prepare Queries node
const user = $('Prepare Queries').item.json;
return [{ json: user }];

const user = $('Check Dedup Result').item.json;

// Completed count
const count_rows = $('Get Completed Count').all();
const completed_count = parseInt(count_rows?.[0]?.json?.completed_count ?? '0', 10) || 0;

// Content preview
const content_rows = $('Get Content Preview').all();
let preview_lines = '';

if (user.is_story) {
  const row = content_rows?.[0]?.json;
  const card_data = typeof row?.card_data === 'string'
    ? JSON.parse(row.card_data)
    : (row?.card_data ?? {});
  if (card_data.hook_text) {
    preview_lines = `오늘의 이야기:\n${card_data.hook_text}`;
  }
} else {
  // Group cards by stage_id to pair title + description
  const by_stage = {};
  for (const row of content_rows) {
    const r = row.json;
    if (!by_stage[r.stage_id]) by_stage[r.stage_id] = {};
    const cd = typeof r.card_data === 'string' ? JSON.parse(r.card_data) : (r.card_data ?? {});
    by_stage[r.stage_id][r.card_type] = cd;
  }
  const words = [];
  for (const [, cards] of Object.entries(by_stage)) {
    const word    = cards['title']?.text ?? cards['title']?.front ?? '';
    const meaning = cards['description']?.text ?? cards['description']?.back ?? '';
    if (word && meaning) words.push(`• ${word} — ${meaning}`);
    if (words.length >= 3) break;
  }
  preview_lines = words.join('\n');
}

return [{
  json: {
    ...user,
    completed_count,
    preview_lines,
  }
}];

const d = $input.item.json;

const system_prompt = `You are Leni, a 15-year-old German girl who studies languages alongside the user.
Tone: warm, bright, slightly playful. Korean 해요체 (존댓말). Plain text only, no markdown.
Max 1~2 emojis per message. Each message max 4 lines.
Respond ONLY with a JSON object containing exactly two keys: incomplete_message, complete_message.
No preamble, no explanation, no code fences. Just the raw JSON.`;

const user_prompt = `사용자 정보:
- 이름: ${d.display_name}
- 학습 상품: ${d.product_name}
- 오늘 세션: ${d.session_label}
- 전체 완료 세션 수: ${d.completed_count}
- 발송 시간대: ${d.slot_type}

오늘의 학습 콘텐츠 미리보기:
${d.preview_lines || '(콘텐츠 준비 중)'}

---

incomplete_message 작성 조건:
- 세션을 아직 시작하지 않은 사용자에게 보내는 메시지
- 위 단어/표현 중 일부를 자연스럽게 포함
- 학습 링크 클릭을 유도하되 강요하지 않음
- 첫 줄이 가장 흥미로운 훅이 되도록

complete_message 작성 조건:
- 이미 오늘 세션을 완료한 사용자에게 보내는 메시지
- slot_type이 "morning"이면: 오늘 배운 내용 중 단어/표현을 활용하는 팁 또는 복습 유도
- slot_type이 "evening"이면: 내일 배울 것을 예고하는 내용 (위 단어들이 내일 나올 것처럼 자연스럽게)
- 칭찬과 기대감을 함께 담을 것`;

return [{
  json: {
    ...d,
    system_prompt,
    user_prompt,
  }
}];

// Parse OpenAI response and build the nv2_schedules row
const openai_res = $input.item.json;
const user = $('Build OpenAI Prompt').item.json;

// Extract generated messages
let incomplete_message = '';
let complete_message = '';
try {
  const content = openai_res.choices?.[0]?.message?.content ?? '{}';
  const parsed = JSON.parse(content);
  incomplete_message = (parsed.incomplete_message ?? '').trim();
  complete_message = (parsed.complete_message ?? '').trim();
} catch (e) {
  return []; // skip on parse error
}

if (!incomplete_message || !complete_message) return [];

// Build message_body: cheer:HH|product_name|session_label|incomplete_message|||complete_message
const message_body = [
  `${user.hour_tag}|${user.product_name}|${user.session_label}|${incomplete_message}`,
  complete_message,
].join('|||');

// Calculate scheduled_at: convert user's local slot_hour:00 to UTC
// Strategy: find the UTC offset for the user's timezone at today's date
const target_local_iso = `${user.today_local}T${String(user.slot_hour).padStart(2, '0')}:00:00`;
const local_as_utc = new Date(target_local_iso + 'Z'); // treat as UTC first
const ref_local = new Date(new Date().toLocaleString('en-US', { timeZone: user.timezone }));
const tz_offset_ms = new Date().getTime() - ref_local.getTime();
const scheduled_at = new Date(local_as_utc.getTime() + tz_offset_ms).toISOString();

const nudge_origin = $env.NUDGE_SITE_URL ?? 'https://nudge.neowithai.com';
const delivery_url = `${nudge_origin}/sessions/${user.session_id}`;

return [{
  json: {
    auth_user_id: user.auth_user_id,
    schedule_type: 'cheer',
    delivery_url,
    message_body,
    scheduled_at,
  }
}];
